"use client";

/**
 * /chat — cold-start build on @gunjo/ui@0.0.1-alpha.2.
 *
 * Composed from the typed barrel. Discovery notes (black-box):
 *
 *  - ChatTemplate (patterns) is the layout shell: { sidebarList?, sidebarDetail?,
 *    header?, children (message stream), composer? }. It is NOT a fixed-size demo
 *    frame in practice: its root className is
 *      "flex w-[1280px] h-[720px] h-screen w-full overflow-hidden bg-background"
 *    — the w-[1280px]/h-[720px] are dead artifacts; cn() = twMerge, so the later
 *    h-screen/w-full win. So it resolves to a full-bleed, full-height shell.
 *    It hard-codes h-screen though, so it must own the viewport (we keep the page
 *    chrome out of its way). The <main> message stream already has
 *    "flex-1 overflow-y-auto" — so scrolling is the template's job.
 *
 *  - ChatMessage (display) renders avatar + name + timestamp + bubble + actions.
 *    role: "assistant" | "user" | "system". timestamp is a PRE-FORMATTED string
 *    (no Date formatting inside the component) — good, lets us avoid hydration
 *    mismatch. isTyping + empty content => animated "typing…" caret. Default
 *    actions (copy/branch/raw or copy/edit) appear under each non-typing message;
 *    showActions={false} turns them off. Avatar falls back to a Sparkles (assistant)
 *    or User (user) icon when avatarSrc is absent.
 *
 *  - ChatInput (inputs) is the composer. Fully controlled internally:
 *    onSend(message, files?) fires on click or Enter (Shift+Enter = newline,
 *    IME-composition aware). isProcessing swaps Send for a Stop button + disables
 *    input. We turn off attachments/options/model/voice for a clean assistant chat.
 *
 *  - ChatPanel (overlay) is an all-in-one alternative (header + scroll + typing +
 *    empty + ChatInput) but it's fixed-height (h-[560px]/h-[420px]) and capped at
 *    max-w-2xl — great for a docked widget, not a full-page chat. We use the
 *    template + primitives instead for a real full-page surface and to own scroll.
 *
 *  - EmptyState (display): { icon?, title, description?, action? } — used for the
 *    empty conversation.
 *
 * Auto-scroll + typing simulation are ours (the template doesn't manage state).
 */

import * as React from "react";
import {
  IconMessageCircle,
  IconSparkles,
} from "@tabler/icons-react";
import {
  Avatar,
  AvatarFallback,
  Badge,
  ChatInput,
  ChatMessage,
  ChatTemplate,
  EmptyState,
} from "@gunjo/ui";

type Author = "user" | "assistant";

interface Message {
  id: string;
  role: Author;
  content: string;
  /** Pre-formatted display string. Filled lazily on the client to stay SSR-safe. */
  timestamp?: string;
}

const USER_NAME = "あなた";
const ASSISTANT_NAME = "Gunjo Assistant";

// Seed conversation. Timestamps are plain static strings (no Date()), so server
// and client render identically — no hydration mismatch.
const SEED_MESSAGES: Message[] = [
  {
    id: "m1",
    role: "assistant",
    content:
      "こんにちは。Gunjo Assistant です。プロダクトのこと、コードのこと、何でも聞いてください。",
    timestamp: "9:41",
  },
  {
    id: "m2",
    role: "user",
    content: "@gunjo/ui でチャット画面を作りたいんだけど、どこから始めればいい？",
    timestamp: "9:41",
  },
  {
    id: "m3",
    role: "assistant",
    content:
      "ChatTemplate をシェルにして、メッセージは ChatMessage、入力欄は ChatInput を置くのが王道です。下の入力欄から実際に送ってみてください — 返信をシミュレートします。",
    timestamp: "9:42",
  },
];

// Canned replies for the simulated assistant.
const CANNED_REPLIES = [
  "なるほど、了解しました。続けてどうぞ。",
  "それは ChatInput の onSend で受け取って、リストに append するだけで動きますよ。",
  "いい質問ですね。ChatMessage は role で見た目が切り替わります。",
  "Enter で送信、Shift+Enter で改行です。日本語入力中の確定 Enter は送信されません。",
  "メッセージが増えても、一番下まで自動でスクロールします。",
];

function formatNow(): string {
  // Client-only formatting (called inside event handlers / effects), so it never
  // runs during SSR and can't cause a hydration mismatch.
  return new Date().toLocaleTimeString([], { hour: "numeric", minute: "2-digit" });
}

let replyCounter = 0;

export default function ChatPage() {
  const [messages, setMessages] = React.useState<Message[]>(SEED_MESSAGES);
  const [isTyping, setIsTyping] = React.useState(false);

  const scrollRef = React.useRef<HTMLDivElement | null>(null);
  const typingTimer = React.useRef<ReturnType<typeof setTimeout> | null>(null);

  const scrollToBottom = React.useCallback(() => {
    const node = scrollRef.current;
    if (!node) return;
    // The scroll container is ChatTemplate's <main>; walk up from our sentinel.
    const scroller = node.parentElement;
    if (!scroller) return;
    const reduceMotion =
      typeof window !== "undefined" &&
      window.matchMedia("(prefers-reduced-motion: reduce)").matches;
    scroller.scrollTo({
      top: scroller.scrollHeight,
      behavior: reduceMotion ? "auto" : "smooth",
    });
  }, []);

  // Keep pinned to the bottom whenever the stream or typing state changes.
  React.useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping, scrollToBottom]);

  React.useEffect(() => {
    return () => {
      if (typingTimer.current) clearTimeout(typingTimer.current);
    };
  }, []);

  const handleSend = React.useCallback(
    (raw: string) => {
      const text = raw.trim();
      if (!text) return;

      const userMessage: Message = {
        id: `u-${Date.now()}`,
        role: "user",
        content: text,
        timestamp: formatNow(),
      };
      setMessages((prev) => [...prev, userMessage]);

      // Simulated assistant: show typing…, then append a reply.
      setIsTyping(true);
      if (typingTimer.current) clearTimeout(typingTimer.current);
      typingTimer.current = setTimeout(() => {
        const reply = CANNED_REPLIES[replyCounter % CANNED_REPLIES.length];
        replyCounter += 1;
        setMessages((prev) => [
          ...prev,
          {
            id: `a-${Date.now()}`,
            role: "assistant",
            content: reply,
            timestamp: formatNow(),
          },
        ]);
        setIsTyping(false);
      }, 1100);
    },
    []
  );

  const isEmpty = messages.length === 0;

  const header = (
    <div className="flex w-full items-center gap-3">
      <Avatar className="h-9 w-9 bg-primary text-primary-foreground">
        <AvatarFallback className="bg-transparent text-primary-foreground">
          <IconSparkles className="h-4 w-4" />
        </AvatarFallback>
      </Avatar>
      <div className="min-w-0 flex-1">
        <p className="truncate text-sm font-semibold text-foreground">
          {ASSISTANT_NAME}
        </p>
        <p className="truncate text-xs text-muted-foreground">
          @gunjo/ui コンポーネントの相談相手
        </p>
      </div>
      <Badge variant="secondary" className="gap-1.5">
        <span className="h-1.5 w-1.5 rounded-full bg-success" aria-hidden />
        オンライン
      </Badge>
    </div>
  );

  const composer = (
    <div className="mx-auto w-full max-w-3xl">
      <ChatInput
        onSend={handleSend}
        isProcessing={isTyping}
        placeholder="メッセージを入力… (Enter で送信 / Shift+Enter で改行)"
        enableAttachments={false}
        showOptionsButton={false}
        showModelSelector={false}
        showVoiceButton={false}
      />
    </div>
  );

  return (
    <ChatTemplate header={header} composer={composer} className="h-screen">
      {/* Message stream lives inside ChatTemplate's <main className="flex-1 overflow-y-auto">. */}
      {isEmpty ? (
        <div className="flex min-h-full items-center justify-center">
          <EmptyState
            icon={<IconMessageCircle className="h-6 w-6" />}
            title="まだメッセージはありません"
            description="下の入力欄から会話を始めましょう。"
          />
        </div>
      ) : (
        <div className="mx-auto flex w-full max-w-3xl flex-col gap-1">
          {messages.map((message) => (
            <ChatMessage
              key={message.id}
              role={message.role}
              content={message.content}
              userName={message.role === "user" ? USER_NAME : ASSISTANT_NAME}
              timestamp={message.timestamp}
              showActions={false}
            />
          ))}

          {isTyping ? (
            <ChatMessage
              role="assistant"
              content=""
              isTyping
              userName={ASSISTANT_NAME}
              showActions={false}
            />
          ) : null}
        </div>
      )}

      {/* Scroll sentinel — used to find the scroll container and pin to bottom. */}
      <div ref={scrollRef} aria-hidden className="h-0 w-0" />
    </ChatTemplate>
  );
}
